Source code in <code>toast/observation.py</code> <pre><code>def __eq__(self, other, approx=False):
    # Note that testing for equality is quite expensive, since it means testing all
    # metadata and also all detector, shared, and interval data.  This is mainly
    # used for unit tests.
    log = Logger.get()
    fail = 0
    if self.name != other.name:
        fail = 1
        log.verbose(
            f"Proc {self.comm.world_rank}:  Obs names {self.name} != {other.name}"
        )
    if self.uid != other.uid:
        fail = 1
        log.verbose(
            f"Proc {self.comm.world_rank}:  Obs uid {self.uid} != {other.uid}"
        )
    if self.telescope != other.telescope:
        fail = 1
        log.verbose(f"Proc {self.comm.world_rank}:  Obs telescopes not equal")
    if self.session != other.session:
        fail = 1
        log.verbose(f"Proc {self.comm.world_rank}:  Obs sessions not equal")
    if self.dist != other.dist:
        fail = 1
        log.verbose(f"Proc {self.comm.world_rank}:  Obs distributions not equal")
    if self.local_detector_flags != other.local_detector_flags:
        fail = 1
        msg = f"Proc {self.comm.world_rank}:  Obs local_detector_flags not equal: "
        msg += f"LFLAGS = {self.local_detector_flags}, "
        msg += f"RFLAGS = {other.local_detector_flags}"
        log.verbose(msg)

    rmeta = self.meta_equal(other, f"Proc {self.comm.world_rank}:  Obs _internal")
    if not rmeta:
        fail = 1
        log.verbose(f"Proc {self.comm.world_rank}:  Obs meta data not equal")

    if self.shared != other.shared:
        fail = 1
        log.verbose(f"Proc {self.comm.world_rank}:  Obs shared data not equal")
    if not self.detdata.__eq__(other.detdata, approx=approx):
        fail = 1
        log.verbose(f"Proc {self.comm.world_rank}:  Obs detdata not equal")
    if self.intervals != other.intervals:
        fail = 1
        log.verbose(f"Proc {self.comm.world_rank}:  Obs intervals not equal")

    # Handle other arbitrary attributes.
    self_attrs = list()
    for k, v in vars(self).items():
        if k.startswith("_"):
            continue
        if k in self._reserved:
            continue
        self_attrs.append(k)
    other_attrs = list()
    for k, v in vars(other).items():
        if k.startswith("_"):
            continue
        if k in self._reserved:
            continue
        other_attrs.append(k)
    if other_attrs != self_attrs:
        fail = 1
        msg = f"Proc {self.comm.world_rank}:  Obs attr lists not equal "
        msg += f"{other_attrs} != {self_attrs}"
        log.verbose(msg)
    else:
        for attr in self_attrs:
            self_obj = getattr(self, attr)
            other_obj = getattr(other, attr)
            if self_obj != other_obj:
                fail = 1
                log.verbose(
                    f"Proc {self.comm.world_rank}:  Obs attr {attr} not equal"
                )

    if self.comm.comm_group is not None:
        fail = self.comm.comm_group.allreduce(fail, op=MPI.SUM)
    return fail == 0
