Source code in <code>toast/ops/simple_jumpcorrect.py</code> <pre><code>@function_timer
def _exec(self, data, detectors=None, **kwargs):
    log = Logger.get()

    if self.save_jumps is not None and self.apply_jumps is not None:
        msg = "Cannot both save to and apply pre-existing jumps"
        raise RuntimeError(msg)

    for ob in data.obs:
        if not ob.is_distributed_by_detector:
            msg = "Observation data must be distributed by detector, not samples"
            log.error(msg)
            raise RuntimeError(msg)
        views = ob.intervals[self.view]
        focalplane = ob.telescope.focalplane

        local_dets = ob.select_local_detectors(flagmask=self.det_mask)
        shared_flags = ob.shared[self.shared_flags].data &amp; self.shared_flag_mask
        if self.phase is None:
            phase = ob.shared[self.phase].data
            phase = np.unwrap(phase)
        else:
            phase = None
        if self.save_jumps is not None:
            jump_props = dict()
        for det in local_dets:
            if self.save_jumps is None:
                jumps = None
            else:
                jumps = list()
            sig = ob.detdata[self.det_data][det]
            det_flags = ob.detdata[self.det_flags][det]
            if self.reset_det_flags:
                det_flags[:] = 0
            bad = np.logical_or(
                shared_flags != 0,
                (det_flags &amp; self.det_flag_mask) != 0,
            )
            # If we are filling gaps with a polynomial, do that now *before*
            # applying a matched filter.
            if self.fill_gaps:
                buffer_fill = int(
                    self.fill_gaps_buffer_time.to_value(u.s)
                    * focalplane.sample_rate.to_value(u.Hz)
                )
                flagged_noise_fill(
                    sig,
                    bad,
                    buffer_fill,
                    poly_order=self.fill_gaps_order,
                    no_white_noise=True,
                )

            if self.apply_jumps is not None:
                corrected_signal, flag_out = self._remove_jumps(
                    sig, bad, ob[self.apply_jumps][det], self.jump_radius
                )
                sig[:] = corrected_signal
                det_flags[flag_out] |= self.jump_mask
            else:
                total_jumps = 0
                for iview, view in enumerate(views):
                    ind = slice(view.first, view.last)
                    view_jumps = self._find_jumps(
                        sig[ind],
                        bad[ind],
                        phase=phase,
                        offset=view.first,
                    )
                    if len(view_jumps) == 0:
                        continue
                    total_jumps += len(view_jumps)
                    corrected_signal, flag_out = self._remove_jumps(
                        sig[ind],
                        bad[ind],
                        view_jumps,
                    )
                    sig[ind] = corrected_signal
                    det_flags[ind][flag_out] |= self.jump_mask
                    if self.save_jumps is not None:
                        jumps.extend(view_jumps)
                if total_jumps &gt; self.njump_limit:
                    det_flags[ind] |= self.det_flag_mask
                if self.save_jumps is not None:
                    jump_props[det] = jumps
                if (
                    np.count_nonzero(
                        det_flags &amp; (self.det_flag_mask | self.jump_mask)
                    )
                    &gt; len(sig) - self.nsample_min
                ):
                    # Too many flagged samples, cut the detector
                    ob.update_local_detector_flags({det: self.jump_mask})
                elif self.fill_gaps:
                    flagged_noise_fill(
                        ob.detdata[self.det_data][det],
                        ob.detdata[self.det_flags][det],
                        buffer_fill,
                        poly_order=self.fill_gaps_order,
                        no_white_noise=True,
                    )

        if self.save_jumps is not None:
            ob[self.save_jumps] = jump_props

    return
