    )
    my_all = list()
    for name in demod_det_data["name"]:
        my_all.append(name)

    demod_focalplane = Focalplane(
        detector_data=demod_det_data,
        field_of_view=focalplane.field_of_view,
        sample_rate=focalplane.sample_rate / self.nskip,
